```java
@Configuration @EnableCaching
public class FlipkartCacheConfig {

    @Bean
    public RedisCacheManager cacheManager(RedisConnectionFactory factory) {
        var serializer = new GenericJackson2JsonRedisSerializer();
        var valueSerializer = RedisSerializationContext.SerializationPair
            .fromSerializer(serializer);

        var defaultConfig = RedisCacheConfiguration.defaultCacheConfig()
            .serializeValuesWith(valueSerializer)
            .disableCachingNullValues();

        return RedisCacheManager.builder(factory)
            .cacheDefaults(defaultConfig.entryTtl(Duration.ofMinutes(5)))
            .withInitialCacheConfigurations(Map.of(
                "products",   defaultConfig.entryTtl(Duration.ofMinutes(10)),
                "categories", defaultConfig.entryTtl(Duration.ofHours(1)),
                "search",     defaultConfig.entryTtl(Duration.ofMinutes(2))
            ))
            .build();
    }
}
```

```java
@Service
public class ProductService {
    private final ProductRepository repo;
    ProductService(ProductRepository r) { repo = r; }

    // Cache individual product by ID for 10 minutes:
    @Cacheable(value = "products", key = "#id")
    public Optional<Product> findById(String id) {
        System.out.println("[DB HIT] Loading product " + id);  // visible in logs
        return repo.findById(id);
    }

    // Cache category listing for 1 hour:
    @Cacheable(value = "categories", key = "#category")
    public List<Product> findByCategory(String category) {
        return repo.findByCategoryIgnoreCase(category);
    }

    // Cache search results for 2 minutes:
    @Cacheable(value = "search", key = "#query.toLowerCase()")
    public List<Product> search(String query) {
        return repo.findByNameContainingIgnoreCase(query);
    }

    // On update: evict the product from cache; categories may also need refresh:
    @CacheEvict(value = "products", key = "#product.id")
    @CacheEvict(value = "categories", allEntries = true)  // ← multiple annotations
    @Transactional
    public Product update(Product product) {
        return repo.save(product);
    }

    // On delete: evict from all caches:
    @Caching(evict = {
        @CacheEvict(value = "products",   key = "#id"),
        @CacheEvict(value = "categories", allEntries = true),
        @CacheEvict(value = "search",     allEntries = true)
    })
    @Transactional
    public void delete(String id) { repo.deleteById(id); }
}
```

